import React from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Card, Row, Col, Statistic, Table, 
  Tabs, Progress, Typography, Space, Tooltip, Breadcrumb 
} from "antd";
import { 
  BarChartOutlined, UserOutlined, WarningOutlined, 
  ArrowUpOutlined, DashboardOutlined, FieldTimeOutlined, HomeOutlined 
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";

const { useToken } = theme;
const { Title, Text } = Typography;

export default function StatisticsPage() {
  const { token } = useToken();
  const { t } = useTranslation(["stats", "common"]);

  // 1. Overall Tab Content
  const renderOverall = () => (
    <div style={{ padding: "16px 0" }}>
      <Row gutter={[16, 16]}>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary }}>
            <Statistic title={t("overall.totalProcessed")} value={125430} suffix={t("unitItems", { ns: "common" })} prefix={<DashboardOutlined />} />
            <Progress percent={76} size="small" status="active" />
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary }}>
            <Statistic title={t("overall.goal達成Rate")} value={88.4} suffix="%" valueStyle={{ color: token.colorSuccess }} prefix={<ArrowUpOutlined />} />
            <Text type="secondary" style={{ fontSize: 11 }}>Target: 142,000</Text>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary }}>
            <Statistic title={t("overall.avgDaily")} value={3420} suffix={t("unitItems", { ns: "common" })} prefix={<BarChartOutlined />} />
            <Text type="secondary" style={{ fontSize: 11 }}>Last 7 Days</Text>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary }}>
            <Statistic title={t("overall.expectedFinish")} value="2026-05-12" prefix={<FieldTimeOutlined />} />
            <Text type="secondary" style={{ fontSize: 11 }}>D-34 Days remain</Text>
          </Card>
        </Col>
      </Row>

      <Card title={t("overall.dailyTrend")} variant="borderless" style={{ marginTop: 16 }}>
        <ReactECharts 
          option={{
            backgroundColor: 'transparent',
            tooltip: { trigger: 'axis' },
            grid: { left: '3%', right: '4%', bottom: '3%', containLabel: true },
            xAxis: { type: 'category', data: ['04-01', '04-02', '04-03', '04-04', '04-05', '04-06', '04-07'], axisLabel: { color: token.colorTextDescription } },
            yAxis: { type: 'value', axisLabel: { color: token.colorTextDescription }, splitLine: { lineStyle: { color: token.colorBorder } } },
            series: [{
              name: t("charts.count"),
              type: 'line',
              smooth: true,
              data: [2800, 3100, 2900, 3500, 3800, 3300, 4100],
              itemStyle: { color: token.colorPrimary },
              areaStyle: { opacity: 0.1 }
            }]
          }} 
          style={{ height: 300 }}
        />
      </Card>
    </div>
  );

  // 2. Personal Performance Tab
  const renderPersonal = () => {
    const columns = [
      { title: t("personal.worker"), dataIndex: "name", key: "name", render: (n: string) => <Space><UserOutlined />{n}</Space> },
      { title: t("personal.processed"), dataIndex: "total", key: "total", align: "right" as const },
      { title: t("personal.speed"), dataIndex: "speed", key: "speed", align: "center" as const },
      { title: t("personal.accuracy"), dataIndex: "accuracy", key: "accuracy", render: (v: number) => <Progress percent={v} size={[-1, 10]} strokeColor={v > 95 ? token.colorSuccess : token.colorWarning} /> },
      { title: t("personal.rejection"), dataIndex: "rejection", key: "rejection", align: "right" as const }
    ];

    const data = [
      { key: 1, name: "Kim Worker", total: "14,200", speed: 450, accuracy: 98.2, rejection: 12 },
      { key: 2, name: "Lee Manager", total: "12,100", speed: 410, accuracy: 96.5, rejection: 24 },
      { key: 3, name: "Park Labeler", total: "10,500", speed: 380, accuracy: 92.1, rejection: 45 },
      { key: 4, name: "Choi Checker", total: "9,800", speed: 350, accuracy: 99.1, rejection: 5 },
      { key: 5, name: "Jung Super", total: "8,900", speed: 320, accuracy: 94.4, rejection: 30 },
    ];

    return (
      <div style={{ padding: "16px 0" }}>
        <Card title={t("personal.ranking")} variant="borderless">
          <Table dataSource={data} columns={columns} pagination={false} size="small" />
        </Card>
      </div>
    );
  };

  // 3. Defect Analysis Tab
  const renderDefect = () => (
    <div style={{ padding: "16px 0" }}>
      <Row gutter={[16, 16]}>
        <Col span={12}>
          <Card title={t("defect.categoryDist")} variant="borderless">
            <ReactECharts 
              option={{
                tooltip: { trigger: 'item' },
                series: [{
                  type: 'pie',
                  radius: ['40%', '70%'],
                  data: [
                    { value: 45, name: 'Wrong Class' },
                    { value: 25, name: 'Missed Object' },
                    { value: 15, name: 'Low Quality' },
                    { value: 10, name: 'Duplicate' },
                    { value: 5, name: 'Other' }
                  ],
                  label: { color: token.colorTextDescription }
                }]
              }}
              style={{ height: 300 }}
            />
          </Card>
        </Col>
        <Col span={12}>
          <Card title={t("defect.classDist")} variant="borderless">
            <ReactECharts 
              option={{
                xAxis: { type: 'category', data: ['Car', 'Pedest', 'Truck', 'Cyclist', 'Sign'], axisLabel: { color: token.colorTextDescription } },
                yAxis: { type: 'value', axisLabel: { color: token.colorTextDescription } },
                series: [{
                  data: [120, 80, 150, 40, 70],
                  type: 'bar',
                  itemStyle: { color: token.colorError }
                }]
              }}
              style={{ height: 300 }}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );

  const items = [
    { key: "1", label: t("tabs.overall"), children: renderOverall() },
    { key: "2", label: t("tabs.personal"), children: renderPersonal() },
    { key: "3", label: t("tabs.defect"), children: renderDefect() },
  ];

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("title")}</Title>
          <Text type="secondary" style={{ fontSize: 12 }}>{t("subtitle")}</Text>
        </div>
        <Breadcrumb 
          items={[
            { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
            { title: t("title") }
          ]} 
        />
      </div>

      <Tabs 
        defaultActiveKey="1" 
        items={items} 
        style={{ background: token.colorBgContainer, padding: "12px 24px", borderRadius: 12, boxShadow: token.boxShadowTertiary }} 
      />
    </div>
  );
}
